#include "bitmaps.h"
#include "gw_lcd.h"
#include "gw_malloc.h"

#pragma GCC optimize("Os")

#if !defined(BIG_BANK)
#define BIG_BANK 1
#endif
#define MAX_LOGO_COUNT 100
#define LOGO_DATA      __attribute__((section(".sdcard_logo")))
#define GFX_DATA       __attribute__((section(".intflash_logo")))
#define INT_LOGO_DATA  __attribute__((section(".intflash_logo")))
#define INT_LOGO_COUNT 3

static retro_logo_image** logo_image_cache;
static int logo_image_count = 0; /* # entries loaded from logo.bin (for bounds check) */

void rg_reset_logo_buffers() {
    logo_image_cache = NULL;
    logo_image_count = 0;
}

retro_logo_image *rg_get_logo(int16_t logo_index) {
    uint8_t header[4];
    uint16_t width, height;
    size_t read;
    if (logo_index < 0)
        return NULL;

    // Logos always included in internal flash.
    // Must be at beginning of the logo list.
    switch (logo_index) {
        case RG_LOGO_RGO:
            return (retro_logo_image *)&logo_rgo;
        case RG_LOGO_RGW:
            return (retro_logo_image *)&logo_rgw;
        case RG_LOGO_GNW:
            return (retro_logo_image *)&logo_gnw;
    }

    static_assert(INT_LOGO_COUNT == 3);
    logo_index -= INT_LOGO_COUNT;

    if (logo_image_cache != NULL) {
        return (logo_index >= 0 && logo_index < logo_image_count) ? logo_image_cache[logo_index] : NULL;
    }

    FILE* file = fopen("/bios/logo.bin", "rb");
    if (!file) {
        printf("Error: unable to open logo file\n");
        return NULL;
    }

    /* ITCM is only 64 KB and shared with all the hot .itcm code; as systems were
     * added it can no longer hold the whole logo cache. Fall back to the main heap
     * (logos are drawn rarely, so they don't need fast TCM) and never crash on OOM. */
    logo_image_cache = itc_malloc(MAX_LOGO_COUNT * sizeof(retro_logo_image*));
    if (logo_image_cache == (void *)0xffffffff)
        logo_image_cache = malloc(MAX_LOGO_COUNT * sizeof(retro_logo_image*));
    if (logo_image_cache == NULL) { fclose(file); return NULL; }

    int current_logo_index = 0;
    while (1) {
        if (fread(header, 1, 4, file) != 4)
            break;

        width = (uint16_t)(header[0] | ((uint16_t)header[1] << 8));
        height = (uint16_t)(header[2] | ((uint16_t)header[3] << 8));

        /* Reject a malformed / stale / past-the-end logo.bin entry: the LCD is
         * 320x240, so any larger dimension is garbage. Without this, a bad header
         * yields a huge data_size and the allocation below OOMs at boot (this was
         * the FATAL EXCEPTION on device — 184 KB request on the ~82 KB heap). */
        if (width == 0 || height == 0 || width > 320 || height > 240)
            break;

        /* Logo bitmaps in logo.bin are packed at exactly ((width+7)>>3)*height bytes
         * with NO inter-entry padding. The old "(data_size+3)&~3" 4-byte alignment
         * over-read on any logo whose row-byte count is odd (e.g. 152x18 = 19 B/row),
         * drifting the parser into garbage after the first such entry — which dropped
         * every later title and triggered the giant bogus allocation. Match the data. */
        size_t data_size = ((width + 7) >> 3) * height;

        retro_logo_image* dest = itc_malloc(sizeof(retro_logo_image) + data_size);
        if (dest == (void *)0xffffffff)
            dest = malloc(sizeof(retro_logo_image) + data_size);
        if (dest == NULL) break;
        dest->width = width;
        dest->height = height;
        read = fread(dest->logo, 1, data_size, file);
        if (read == 0) break;

        logo_image_cache[current_logo_index] = dest;
        current_logo_index++;
        if (current_logo_index >= MAX_LOGO_COUNT) break; /* never overflow the cache */
    }

    fclose(file);
    logo_image_count = current_logo_index;
    return (logo_index >= 0 && logo_index < logo_image_count) ? logo_image_cache[logo_index] : NULL;
}

